import { test, expect } from '@playwright/test';

test.use({ storageState: 'studio/.auth/successfactors.json' });

test('HR admin onboarding: Data Collection and Compliance status check for Matthew Moraga', async ({ page }) => {
  await test.step('Navigate to Performance Manager start URL', async () => {
    await page.goto('https://performancemanager8.successfactors.com/sf/start');
  });

  await test.step('Open Home menu and select Onboarding', async () => {
    await page.getByRole('button', { name: 'Home' }).click();
    await page.waitForTimeout(1500);
    await page.getByRole('menuitem', { name: 'Onboarding' }).click();
    await page.waitForTimeout(1500);
  });

  await test.step('Search for candidate "Matthew Moraga"', async () => {
    await page.locator('input[placeholder="Search for new recruit"]').fill('Matthew Moraga');
    await page.waitForTimeout(1500);
    await page.getByRole('option', { name: /^Matthew Moraga/ }).click();
    await page.waitForTimeout(1500);
    await page.locator('input[placeholder="Search for new recruit"]').press('Enter');
    await page.waitForTimeout(1500);
  });

  await test.step('Check Data Collection and Compliance status', async () => {
    // Wait for the table row to appear
    const tableRow = page.locator('ui5-table-row');
    await expect(tableRow).toBeVisible();

    // Read Data Collection status (4th cell)
    const dataCollectionCell = tableRow.locator('ui5-table-cell').nth(3);
    const dataCollectionStatus = (await dataCollectionCell.textContent())?.trim();

    // Read Compliance Forms status (5th cell)
    const complianceCell = tableRow.locator('ui5-table-cell').nth(4);
    const complianceStatus = (await complianceCell.textContent())?.trim();

    // Conditional logic for test pass/fail
    if (dataCollectionStatus === 'Completed' && complianceStatus === 'Completed') {
      // Path A: Both statuses are Completed
      expect(dataCollectionStatus).toBe('Completed');
      expect(complianceStatus).toBe('Completed');
    } else {
      // Path B: One or both statuses are not Completed
      throw new Error(
        `Onboarding status check failed: Data Collection="${dataCollectionStatus}", Compliance Forms="${complianceStatus}"`
      );
    }
  });
});
